'use client';

import { createContext, useContext, useState, type ReactNode, type Dispatch, type SetStateAction } from 'react';

type Theme = 'light' | 'dark';
type AppContextValue = { theme: Theme; setTheme: Dispatch<SetStateAction<Theme>> };
const AppContext = createContext<AppContextValue | undefined>(undefined);

export function AppProvider({ children }: { children: ReactNode }) {
  const [theme, setTheme] = useState<Theme>('light');
  return <AppContext.Provider value={{ theme, setTheme }}>{children}</AppContext.Provider>;
}

export function useAppContext(): AppContextValue {
  const context = useContext(AppContext);
  if (!context) throw new Error('useAppContext must be used within AppProvider');
  return context;
}

export type Post = { id: number; title: string; body: string; userId?: number };
export type Comment = { id: number; postId?: number; name: string; email: string; body: string };

const API = 'https://jsonplaceholder.typicode.com';

export async function getPosts(limit?: number, revalidate = 60): Promise<Post[]> {
  const response = await fetch(`${API}/posts${limit ? `?_limit=${limit}` : ''}`, { next: { revalidate } });
  if (!response.ok) throw new Error('Unable to load posts');
  return response.json() as Promise<Post[]>;
}

export async function getPost(id: string, revalidate = 300): Promise<{ post: Post; comments: Comment[] } | null> {
  const [postResponse, commentsResponse] = await Promise.all([
    fetch(`${API}/posts/${encodeURIComponent(id)}`, { next: { revalidate } }),
    fetch(`${API}/posts/${encodeURIComponent(id)}/comments`, { next: { revalidate } }),
  ]);
  if (!postResponse.ok || !commentsResponse.ok) return null;
  return { post: await postResponse.json() as Post, comments: await commentsResponse.json() as Comment[] };
}

