import { NextResponse } from 'next/server';

type CreatePost = { title?: string; content?: string };

export async function GET() {
  return NextResponse.json([{ id: 1, title: 'First Post', content: 'This is the first post' }, { id: 2, title: 'Second Post', content: 'This is the second post' }]);
}

export async function POST(request: Request) {
  const { title, content } = await request.json() as CreatePost;
  if (!title || !content) return NextResponse.json({ error: 'Title and content are required' }, { status: 400 });
  return NextResponse.json({ id: Date.now(), title, content, createdAt: new Date().toISOString() }, { status: 201 });
}

import { NextResponse } from 'next/server';

type RouteContext = { params: Promise<{ id: string }> };
type PostInput = { title?: string; content?: string };

export async function GET(_request: Request, { params }: RouteContext) {
  const { id } = await params;
  return NextResponse.json({ id: Number.parseInt(id, 10), title: `Post ${id}`, content: `This is the content for post ${id}`, createdAt: new Date().toISOString() });
}

export async function PUT(request: Request, { params }: RouteContext) {
  const { id } = await params;
  const { title, content } = await request.json() as PostInput;
  return NextResponse.json({ id: Number.parseInt(id, 10), title: title || `Post ${id}`, content: content || `Updated content for post ${id}`, updatedAt: new Date().toISOString() });
}

export async function DELETE(_request: Request, { params }: RouteContext) {
  const { id } = await params;
  return NextResponse.json({ message: `Post ${id} deleted successfully` });
}

